main:
octo.registerCommand("upper", "UPPERCASE", function(t){ return String(t).toUpperCase(); });
octo.registerCommand("lower", "lowercase", function(t){ return String(t).toLowerCase(); });
octo.registerCommand("title", "Title Case", function(t){ return String(t).replace(/\w\S*/g, function(w){ return w.charAt(0).toUpperCase() + w.substr(1).toLowerCase(); }); });
octo.registerCommand("slug", "Slugify", function(t){ return String(t).toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, ""); });
octo.registerCommand("wc", "Append Word Count", function(t){ var s = String(t); var m = s.match(/\S+/g); var n = m ? m.length : 0; return s + "\n\n_Word count: " + n + "_"; });
